package org.example.aop.aspectj

import com.intellij.psi.PsiFile
import com.intellij.psi.util.PsiTreeUtil
import com.intellij.psi.PsiManager
import com.intellij.openapi.project.Project
import com.intellij.psi.search.GlobalSearchScope
import com.intellij.psi.search.FilenameIndex
import com.intellij.psi.search.FileTypeIndex
import com.intellij.util.indexing.FileBasedIndex
import org.example.aop.aspectj.AspectJFileType
import org.example.aop.aspectj.psi.PointcutDeclaration

internal object AspectJReferenceSupport {

    private val pointcutDeclarationRegex = Regex("""(?m)^\s*pointcut\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(""")
    private val importRegex = Regex("""(?m)^\s*import\s+([A-Za-z_][A-Za-z0-9_.]*)\s*;\s*$""")

    fun isAnnotationReference(text: String, fileText: String, startOffset: Int): Boolean {
        return text.startsWith('@') && text.length > 1 && previousNonWhitespaceChar(fileText, startOffset) == '('
    }

    fun isNamedPointcutReference(text: String, fileText: String, startOffset: Int): Boolean {
        if (text.isBlank()) return false
        val previous = previousNonWhitespaceChar(fileText, startOffset)
        return previous == ':' && fileText.indexOf(text, startOffset) == startOffset
    }

    /**
     * Find pointcut declaration by name using PSI tree (new approach)
     */
    fun findPointcutDeclaration(file: PsiFile, pointcutName: String): PointcutDeclaration? {
        return PsiTreeUtil.findChildrenOfType(file, PointcutDeclaration::class.java)
            .firstOrNull { it.getPointcutName() == pointcutName }
    }

    /**
     * Search for a pointcut declaration across the project by scanning all .aj files.
     * This is a fallback solution (no index). It is sufficient for Phase 5 prototype.
     */
    fun findPointcutDeclarationInProject(project: Project, pointcutName: String): PointcutDeclaration? {
        val scope = GlobalSearchScope.projectScope(project)
        val broadScope = GlobalSearchScope.everythingScope(project)
        val psiManager = PsiManager.getInstance(project)

        fun scanFiles(files: Iterable<com.intellij.openapi.vfs.VirtualFile>): PointcutDeclaration? {
            for (vf in files) {
                val psi = psiManager.findFile(vf) ?: continue
                val decl = findPointcutDeclaration(psi, pointcutName)
                if (decl != null) return decl
            }
            return null
        }

        // Fast path: use the project index of named pointcuts.
        try {
            val indexedFiles = FileBasedIndex.getInstance().getContainingFiles(AspectJPointcutIndex.NAME, pointcutName, scope)
            println("[AspectJRef] indexedFiles=${indexedFiles.count()} for $pointcutName")
            scanFiles(indexedFiles)?.let { found ->
                println("[AspectJRef] found via index in ${found.containingFile.name}")
                return found
            }
        } catch (_: Throwable) {
            // ignore and continue with broader scans
        }

        // Fallback 1: all .aj files by extension.
        try {
            val filesByExt = FilenameIndex.getAllFilesByExt(project, "aj", broadScope)
            println("[AspectJRef] filesByExt=${filesByExt.count()} for $pointcutName")
            scanFiles(filesByExt)?.let { found ->
                println("[AspectJRef] found via ext in ${found.containingFile.name}")
                return found
            }
        } catch (_: Throwable) {
            // ignore and continue
        }

        // Fallback 2: all files associated with AspectJFileType.
        try {
            val filesByType = FileTypeIndex.getFiles(AspectJFileType, broadScope)
            println("[AspectJRef] filesByType=${filesByType.count()} for $pointcutName")
            scanFiles(filesByType)?.let { found ->
                println("[AspectJRef] found via filetype in ${found.containingFile.name}")
                return found
            }
        } catch (_: Throwable) {
            // ignore and continue
        }

        // Last resort: walk the project VFS and inspect any .aj files we find.
        val base = project.baseDir ?: return null
        fun visit(vf: com.intellij.openapi.vfs.VirtualFile): PointcutDeclaration? {
            if (vf.isDirectory) {
                for (child in vf.children) {
                    val found = visit(child)
                    if (found != null) return found
                }
            } else if (vf.extension == "aj") {
                val psi = psiManager.findFile(vf) ?: return null
                val decl = findPointcutDeclaration(psi, pointcutName)
                if (decl != null) return decl
            }
            return null
        }
        return visit(base)
    }

    fun collectPointcutNamesInProject(project: Project): Set<String> {
        val names = linkedSetOf<String>()
        try {
            FileBasedIndex.getInstance().processAllKeys(
                AspectJPointcutIndex.NAME,
                { key: String ->
                    names += key
                    true
                },
                GlobalSearchScope.projectScope(project),
                null
            )
        } catch (_: Throwable) {
            // ignore and return what we have
        }
        return names
    }

    /**
     * Find pointcut declaration offset using regex (legacy approach, kept for compatibility)
     */
    fun findPointcutDeclarationOffset(fileText: String, pointcutName: String): Int? {
        return pointcutDeclarationRegex.findAll(fileText).firstOrNull { match ->
            match.groupValues[1] == pointcutName
        }?.groups?.get(1)?.range?.first
    }

    fun findImportedQualifiedName(fileText: String, shortName: String): String? {
        return importRegex.findAll(fileText)
            .map { it.groupValues[1] }
            .firstOrNull { it.substringAfterLast('.') == shortName }
    }

    private fun previousNonWhitespaceChar(text: String, offset: Int): Char? {
        var i = offset - 1
        while (i >= 0 && text[i].isWhitespace()) i--
        return if (i >= 0) text[i] else null
    }
}

package org.example.aop.aspectj.psi

import com.intellij.psi.PsiElement
import com.intellij.psi.PsiReferenceBase
import com.intellij.psi.util.PsiTreeUtil
import org.example.aop.aspectj.AspectJReferenceSupport

/**
 * Reference for pointcut designator references (e.g., in "myPointcut()" within a pointcut expression)
 *
 * Example: @pointcut("execution(...) && myPointcut()")
 *                                     ^^^^^^^^^^
 *                                     This is a designator reference
 *
 * Enables:
 * - Go to Definition (Ctrl+Click)
 * - Find Usages
 * - Rename refactoring
 */
class AspectJPointcutReference(
    element: PsiElement,
    val referenceName: String
) : PsiReferenceBase<PsiElement>(element, true) {

    override fun resolve(): PsiElement? {
        val file = element.containingFile
        AspectJReferenceSupport.findPointcutDeclaration(file, referenceName)
            ?.nameIdentifier
            ?.let { return it }

        AspectJReferenceSupport.findPointcutDeclarationInProject(file.project, referenceName)
            ?.nameIdentifier
            ?.let { return it }

        return file.let {
            PsiTreeUtil.findChildrenOfType(it, PointcutDeclaration::class.java)
                .firstOrNull { decl -> decl.getPointcutName() == referenceName }
                ?.nameIdentifier
        }
    }

    override fun getVariants(): Array<Any> {
        val local = element.containingFile.let {
            PsiTreeUtil.findChildrenOfType(it, PointcutDeclaration::class.java)
                .mapNotNull { decl -> decl.getPointcutName() }
                .distinct()
        }
        val projectNames = AspectJReferenceSupport.collectPointcutNamesInProject(element.containingFile.project)
        return (local + projectNames).distinct().toTypedArray()
    }

    override fun getCanonicalText(): String = referenceName
}

package org.example.aop.aspectj.psi

import com.intellij.psi.PsiElement
import com.intellij.psi.PsiReferenceBase
import com.intellij.psi.util.PsiTreeUtil
import org.example.aop.aspectj.AspectJReferenceSupport

/**
 * Reference for pointcut designator references (e.g., in "myPointcut()" within a pointcut expression)
 *
 * Example: @pointcut("execution(...) && myPointcut()")
 *                                     ^^^^^^^^^^
 *                                     This is a designator reference
 *
 * Enables:
 * - Go to Definition (Ctrl+Click)
 * - Find Usages
 * - Rename refactoring
 */
class AspectJPointcutReference(
    element: PsiElement,
    val referenceName: String
) : PsiReferenceBase<PsiElement>(element, true) {

    override fun resolve(): PsiElement? {
        val file = element.containingFile
        AspectJReferenceSupport.findPointcutDeclaration(file, referenceName)
            ?.let { decl -> return decl.nameIdentifier ?: decl }

        AspectJReferenceSupport.findPointcutDeclarationInProject(file.project, referenceName)
            ?.let { decl -> return decl.nameIdentifier ?: decl }

        return file.let {
            PsiTreeUtil.findChildrenOfType(it, PointcutDeclaration::class.java)
                .firstOrNull { decl -> decl.getPointcutName() == referenceName }
                ?.let { decl -> decl.nameIdentifier ?: decl }
        }
    }

    override fun getVariants(): Array<Any> {
        val local = element.containingFile.let {
            PsiTreeUtil.findChildrenOfType(it, PointcutDeclaration::class.java)
                .mapNotNull { decl -> decl.getPointcutName() }
                .distinct()
        }
        val projectNames = AspectJReferenceSupport.collectPointcutNamesInProject(element.containingFile.project)
        return (local + projectNames).distinct().toTypedArray()
    }

    override fun getCanonicalText(): String = referenceName
}

package org.example.aop.aspectj

import com.intellij.testFramework.fixtures.BasePlatformTestCase
import com.intellij.psi.util.PsiTreeUtil
import org.example.aop.aspectj.psi.AspectJPointcutReference
import org.example.aop.aspectj.psi.DesignatorReference

class AspectJCrossFileReferenceTest : BasePlatformTestCase() {

	fun testPointcutReferenceResolvesAcrossFiles() {
		val declaration = myFixture.addFileToProject(
			"lib/Shared.aj",
			"""
				aspect SharedAspect {
					pointcut sharedPointcut() : execution(* shared(..));
				}
			""".trimIndent()
		)

		val usage = myFixture.addFileToProject(
			"Use.aj",
			"""
				aspect UseAspect {
					before() : sharedPointcut() { }
				}
			""".trimIndent()
		)

		myFixture.configureFromExistingVirtualFile(usage.virtualFile)
		val designator = PsiTreeUtil.findChildrenOfType(myFixture.file, DesignatorReference::class.java)
			.firstOrNull { it.referenceName == "sharedPointcut" }

		assertNotNull("Expected a designator reference at the pointcut usage", designator)
		val reference = AspectJPointcutReference(designator!!, designator.referenceName!!)
		val resolved = reference.resolve()

		assertNotNull("Expected the reference to resolve to the declaration in another file", resolved)
		assertEquals("Shared.aj", resolved!!.containingFile.name)
		assertEquals(declaration.virtualFile, resolved.containingFile.virtualFile)
	}

	fun testCrossFileUsageDoesNotLookUndefined() {
		myFixture.addFileToProject(
			"lib/Shared.aj",
			"""
				aspect SharedAspect {
					pointcut sharedPointcut() : execution(* shared(..));
				}
			""".trimIndent()
		)

		val usage = myFixture.addFileToProject(
			"Use.aj",
			"""
				aspect UseAspect {
					before() : sharedPointcut() { }
				}
			""".trimIndent()
		)

		myFixture.configureFromExistingVirtualFile(usage.virtualFile)
		myFixture.enableInspections(AspectJInspection())

		val highlightInfos = myFixture.doHighlighting()
		assertTrue(
			"Cross-file pointcut usage should not be flagged as undefined",
			highlightInfos.none { info -> info.description?.contains("not defined", ignoreCase = true) == true }
		)
	}
}

package org.example.aop.aspectj

import com.intellij.lang.LanguageParserDefinitions
import com.intellij.openapi.application.ApplicationManager
import com.intellij.openapi.fileTypes.FileTypeManager
import com.intellij.openapi.util.Disposer
import com.intellij.testFramework.fixtures.BasePlatformTestCase
import com.intellij.psi.util.PsiTreeUtil
import org.example.aop.aspectj.psi.AspectJPointcutReference
import org.example.aop.aspectj.psi.DesignatorReference

class AspectJCrossFileReferenceTest : BasePlatformTestCase() {

	private var parserDefinition: AspectJParserDefinition? = null

	override fun setUp() {
		super.setUp()
		parserDefinition = AspectJParserDefinition().also { definition ->
			LanguageParserDefinitions.INSTANCE.addExplicitExtension(AspectJLanguage, definition)
			Disposer.register(testRootDisposable) {
				LanguageParserDefinitions.INSTANCE.removeExplicitExtension(AspectJLanguage, definition)
			}
		}
		val fileTypeManager = FileTypeManager.getInstance()
		val alreadyRegistered = fileTypeManager.getAssociations(AspectJFileType)
			.any { matcher -> matcher.acceptsCharSequence("Sample.aj") }
		if (!alreadyRegistered) {
			ApplicationManager.getApplication().runWriteAction {
				fileTypeManager.associateExtension(AspectJFileType, "aj")
			}
		}
	}

	fun testPointcutReferenceResolvesAcrossFiles() {
		val declaration = myFixture.addFileToProject(
			"lib/Shared.aj",
			"""
				aspect SharedAspect {
					pointcut sharedPointcut() : execution(* shared(..));
				}
			""".trimIndent()
		)

		myFixture.configureByText(
			AspectJFileType,
			"""
				aspect UseAspect {
					before() : sharedPointcut() { }
				}
			""".trimIndent()
		)

		val designator = PsiTreeUtil.findChildrenOfType(myFixture.file, DesignatorReference::class.java)
			.firstOrNull { it.referenceName == "sharedPointcut" }

		assertNotNull("Expected a designator reference at the pointcut usage", designator)
		val reference = AspectJPointcutReference(designator!!, designator.referenceName!!)
		val resolved = reference.resolve()

		assertNotNull("Expected the reference to resolve to the declaration in another file", resolved)
		assertEquals("Shared.aj", resolved!!.containingFile.name)
		assertEquals(declaration.virtualFile, resolved.containingFile.virtualFile)
	}

	fun testCrossFileUsageDoesNotLookUndefined() {
		myFixture.addFileToProject(
			"lib/Shared.aj",
			"""
				aspect SharedAspect {
					pointcut sharedPointcut() : execution(* shared(..));
				}
			""".trimIndent()
		)

		myFixture.configureByText(
			AspectJFileType,
			"""
				aspect UseAspect {
					before() : sharedPointcut() { }
				}
			""".trimIndent()
		)

		myFixture.enableInspections(AspectJInspection())

		val highlightInfos = myFixture.doHighlighting()
		assertTrue(
			"Cross-file pointcut usage should not be flagged as undefined",
			highlightInfos.none { info -> info.description?.contains("not defined", ignoreCase = true) == true }
		)
	}
}
